INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'mess', 'Mess > Notes: South Indian style cuisine. Chicken served on Sunday lunch/dinner and Wednesday lunch. Boiled egg served on Wednesday, Thursday, and Saturday breakfast and Thursday dinner.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'mess', 'Mess > Cuisine: Predominantly South Indian with Tamil Nadu style dishes (sambar, rasam, poriyal, pongal, dosa). Non-veg options include chicken and egg.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > Program: B.Tech Semester VIII (CSAB/JoSAA admission), Academic Year 2025-26.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > GEN/OBC/EWS (Income >5L): Rs 67,750 per semester. Includes Tuition Fee Rs 62,500 + Institute fees Rs 5,250.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > GEN/OBC/EWS (Income 1-5L): Rs 26,083 per semester. Includes Tuition Fee Rs 20,833 + Institute fees Rs 5,250.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > GEN/OBC/EWS (Income <1L): Rs 5,250 per semester. Tuition Fee waived, only institute fees charged.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > SC/ST/PH: Rs 5,250 per semester. Tuition Fee waived, only institute fees charged.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > B.Tech Semester IV & VI (CSAB/JoSAA): GEN >5L Rs 67,950, GEN 1-5L Rs 26,283, GEN <1L Rs 5,450, SC/ST Rs 5,450.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > DASA/SII admission: Rs 67,950 total for CIWG/SAARC. Non-CIWG Non-SAARC: USD 4000 tuition + INR 5,450 institute fees.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > Hostel fee: Approximately Rs 30,000 per semester.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > Institute fees breakdown: Computer Fee Rs 1,000, Internet Fee Rs 300, Library Fee Rs 1,000, Association & Cultural Fee Rs 1,000, Sports Centre Rs 500, Registration-Enrollment Fee Rs 200, Examination Fee Rs 350, Student Aid Fee Rs 200, Group Insurance Fee Rs 250, Wellness Fee Rs 200, Training & Placement Fee Rs 250.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > Payment deadlines: Without fine up to 28-01-2026. With Rs 500 fine up to 12-02-2026. With Rs 1000 fine up to 14-03-2026. After 15-03-2026 Rs 1000+ per month additional.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'fee_structure', 'Fee Structure > Payment mode: Only SB Collect or Samarth Portal accepted. Cash, Cheque, and Pay Orders are NOT accepted.');
