INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'elections', 'Elections > Student Council positions: President (III Year), Vice President-1 (III Year, female only), Vice President-2 (II Year), General Secretary-1 (II Year, female only), General Secretary-2 (III BSc BEd / I Year Masters / PhD), Joint Secretary 1-4 (various).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('NIT Puducherry', 'elections', 'Elections > Eligibility: Minimum CGPA 7.00/10, no disciplinary record, must have held positions such as CR/HR/NSS/NCC.');
